16→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
17→    ) {
18→        node
19→            .takeIf { node.elementType == PACKAGE_DIRECTIVE }
20→            ?.firstChildNode
21→            ?.nextCodeSibling()
22→            ?.takeIf { it.elementType == ElementType.DOT_QUALIFIED_EXPRESSION || it.elementType == ElementType.REFERENCE_EXPRESSION }
23→            ?.let { expression ->
24→                if (expression.text.contains('_')) {
