29→                } else if (!expression.text.matches(VALID_PACKAGE_NAME_REGEXP)) {
30→                    emit(expression.startOffset, "Package name contains a disallowed character", false)
31→                }
32→            }
33→    }
34→
35→    private companion object {
36→        val VALID_PACKAGE_NAME_REGEXP = Regex("[a-z_][a-zA-Z\\d_]*(\\.[a-z_][a-zA-Z\\d_]*)*")
