 61→        identifier: ASTNode,
 62→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 63→    ) {
 64→        identifier
 65→            .text
 66→            .takeUnless { it.matches(BACKING_PROPERTY_LOWER_CAMEL_CASE_REGEXP) }
 67→            ?.let {
 68→                emit(identifier.startOffset, "Backing property name should start with underscore followed by lower camel case", false)
 69→            }
 70→    }
