    @Test
    fun `Given a class name containing nordic characters then do not emit`() {
        val code =
            """
            class Ångström
            """.trimIndent()

        KtLintAssertThat.assertThatRule { ClassNamingRule() }(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function name containing nordic characters then do not emit`() {
        val code =
            """
            fun føø() = Unit
            """.trimIndent()

        KtLintAssertThat.assertThatRule { FunctionNamingRule() }(code).hasNoLintViolations()
    }

    @Test
